import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface PomodoroData {
  sessionsCompleted: number;
  totalFocusTime: string;
  dailyGoal: {
    target: string;
    current: string;
    percentage: number;
  };
  sessionHistory: { time: string; duration: number }[];
}

export default function Widget() {
  const pomodoroData = response.data as PomodoroData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#F44336' }}>
              Focus Time
            </Typography>
            <Typography variant="h5" sx={{ color: '#FFC107', fontWeight: 600 }}>
              {pomodoroData.totalFocusTime}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              of {pomodoroData.dailyGoal.target} goal
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#FFC107' }}>
                {pomodoroData.dailyGoal.percentage}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={pomodoroData.dailyGoal.percentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#424242',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FFC107',
                  borderRadius: 4,
                },
              }}
            />
          </Box>

          <Box sx={{ width: '100%', height: 100 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: pomodoroData.sessionHistory.map(session => session.duration),
                  color: '#F44336',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: pomodoroData.sessionHistory.map(session => session.time),
                  id: 'sessions',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#FFFFFF',
                  },
                },
              ]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis axisId="sessions" />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
